export const LEGACY_PORTAL_URL =
  process.env.REACT_APP_LEGACY_PORTAL_URL || 'https://student-insight-hub-alpha.vercel.app/';

export const isAdminLikeRole = (role) => ['admin', 'faculty'].includes(role);

export const isExternalRoute = (route) => /^https?:\/\//i.test(route || '');

export const getDefaultRoute = (user) => (isAdminLikeRole(user?.role) ? '/admin' : LEGACY_PORTAL_URL);

export const redirectToRoute = (route, navigate, options = { replace: true }) => {
  if (isExternalRoute(route)) {
    window.location.replace(route);
    return;
  }

  navigate(route, options);
};

export const getRoleLabel = (role) => {
  switch (role) {
    case 'admin':
      return 'Admin';
    case 'faculty':
      return 'Faculty';
    default:
      return 'User';
  }
};
